Hata yönetimi yok. Dosyanın kapandığından emin olmak için `defer` kullanılmalı.
```go
package main

import "os"

func main() {
    f, err := os.Create("file.txt")
    if err != nil {
        log.Fatal(err)
    }
    defer f.Close()
    if _, err := f.WriteString("hello"); err != nil {
        log.Fatal(err)
    }
}
```

